import { useEffect, useState, useContext } from "react";
import { useNavigate } from "react-router-dom";
import { getVoterElection } from "../../api/electionsApi";
import { UserContext } from "../../context/UserContext";

function Elections() {
  const [election, setElection] = useState(null);
  const { user } = useContext(UserContext);
  const navigate = useNavigate();

  useEffect(() => {
    if (!user?.constituency_id) return;

    getVoterElection(user.constituency_id)
      .then(res => setElection(res.data))
      .catch(err => console.error(err));
  }, [user]);

  if (!election) return <p>No election available</p>;

  return (
    <div>
      <h2>Election</h2>

      <p>
        Status: <b>{election.status}</b>
      </p>

      {election.status === "ONGOING" ? (
        <button onClick={() => navigate("/voter/vote")}>
          Vote Now
        </button>
      ) : (
        <p>Voting is not open yet</p>
      )}
    </div>
  );
}

export default Elections;
